function solve(m, n, waitCost) {
    const dp = new Array(m).fill().map(() => new Array(n).fill(Infinity));
    dp[0][0] = (0 + 1) * (0 + 1); // initial entry cost

    const directions = [[1, 0], [0, 1]]; // down and right

    let step = 1;
    let updated = true;

    while (updated) {
        updated = false;
        const newDp = new Array(m).fill().map(() => new Array(n).fill(Infinity));

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (dp[i][j] === Infinity) continue;

                if (step % 2 === 1) { // odd step: move
                    for (const [di, dj] of directions) {
                        const ni = i + di;
                        const nj = j + dj;
                        if (ni < m && nj < n) {
                            const cost = dp[i][j] + (ni + 1) * (nj + 1);
                            if (cost < newDp[ni][nj]) {
                                newDp[ni][nj] = cost;
                                updated = true;
                            }
                        }
                    }
                } else { // even step: wait
                    const cost = dp[i][j] + waitCost[i][j];
                    if (cost < newDp[i][j]) {
                        newDp[i][j] = cost;
                        updated = true;
                    }
                }
            }
        }

        if (updated) {
            for (let i = 0; i < m; i++) {
                for (let j = 0; j < n; j++) {
                    dp[i][j] = Math.min(dp[i][j], newDp[i][j]);
                }
            }
        }
        step++;
    }

    return dp[m - 1][n - 1];
}

